class Solution {
    public int strongPasswordChecker(String password) {
        int n = password.length();
        int res = 0;
        int oneLower = 1, oneUpper = 1, oneDigit = 1;

        for (char c : password.toCharArray()) {
            if (Character.isLowerCase(c)) oneLower = 0;
            if (Character.isUpperCase(c)) oneUpper = 0;
            if (Character.isDigit(c)) oneDigit = 0;
        }

        res += oneLower + oneUpper + oneDigit;

        if (n < 6) return Math.max(res, 6 - n);

        int replace = 0, del = n - 20;
        char[] arr = password.toCharArray();

        for (int i = 0; i < n - 2; i++) {
            if (arr[i] == arr[i + 1] && arr[i + 1] == arr[i + 2]) {
                int j = i + 3;
                while (j < n && arr[j] == arr[i]) j++;
                replace += (j - i) / 3;
            }
        }

        if (del > 0) {
            res += del;
            replace -= del;
        }

        return res + Math.max(0, replace);
    }
}
